from dataclasses import dataclass
from enum import Enum

class RiskTolerance(Enum):
    CONSERVATIVE   = "conservative"    # Halt if any HIGH risk is unmitigated
    BALANCED       = "balanced"        # Proceed if HIGH risks have mitigations in place
    PROGRESSIVE    = "progressive"     # Proceed with documented residual risk

@dataclass
class AIGovernancePolicy:
    """GV.1 — Policies and accountability."""
    system_owner: str               # individual accountable for risk decisions
    risk_tolerance: RiskTolerance
    review_cadence_days: int        # how often deployed system is reviewed
    escalation_contacts: list[str]  # who to call for an incident

    def can_deploy(self, unmitigated_high_risks: int) -> bool:
        if self.risk_tolerance == RiskTolerance.CONSERVATIVE:
            return unmitigated_high_risks == 0
        if self.risk_tolerance == RiskTolerance.BALANCED:
            return True   # deployer accepts responsibility for documented mitigations
        return True       # PROGRESSIVE: residual risk accepted with documentation

from dataclasses import dataclass
from typing import Literal

RiskLevel = Literal["LOW", "MEDIUM", "HIGH", "CRITICAL"]

@dataclass
class RiskMeasurement:
    """A single measurement result for one risk category."""
    category: str                      # e.g. "Fairness / Bias"
    metric_name: str                   # e.g. "demographic_parity_difference"
    metric_value: float
    threshold: float                   # organisation-defined acceptable bound
    passes_threshold: bool
    measurement_method: str            # e.g. "held-out test set with demographic labels"
    notes: str = ""

    @property
    def risk_level(self) -> RiskLevel:
        gap = abs(self.metric_value - self.threshold)
        if self.passes_threshold:
            return "LOW" if gap > 0.1 else "MEDIUM"
        return "HIGH" if gap < 0.2 else "CRITICAL"

class MeasureReport:
    def __init__(self, system_context: "AISystemContext"):
        self.context = system_context
        self.measurements: list[RiskMeasurement] = []

    def add(self, m: RiskMeasurement) -> None:
        self.measurements.append(m)

    def failing_measurements(self) -> list[RiskMeasurement]:
        return [m for m in self.measurements if not m.passes_threshold]

    def highest_risk(self) -> RiskLevel:
        levels = {"LOW":0, "MEDIUM":1, "HIGH":2, "CRITICAL":3}
        if not self.measurements:
            return "MEDIUM"   # unknown = at least medium risk
        return max(
            (m.risk_level for m in self.measurements),
            key=lambda l: levels[l]
        )

    def summary(self) -> dict:
        return {
            "system": self.context.system_name,
            "total_measurements": len(self.measurements),
            "failing": len(self.failing_measurements()),
            "highest_risk": self.highest_risk(),
        }

import random
from typing import Callable

def measure_consistency_bias(
    agent_fn: Callable[[str], str],
    prompt_template: str,
    groups: dict[str, list[str]],   # {"gender": ["male name", "female name"], ...}
    n_samples: int = 50,
) -> dict[str, float]:
    """
    Measure whether an agent's response changes when the only difference
    is a demographic attribute in the prompt.
    Returns mean output-length ratio per attribute group (proxy for treatment difference).
    """
    results: dict[str, list[int]] = {attr: [] for attr in groups}

    for _ in range(n_samples):
        for attr, values in groups.items():
            for val in values:
                prompt = prompt_template.replace("{subject}", val)
                response = agent_fn(prompt)
                results[attr].append(len(response))

    # Compute coefficient of variation per attribute — high variance = potential bias
    stats = {}
    for attr, lengths in results.items():
        mean = sum(lengths) / len(lengths)
        variance = sum((x - mean) ** 2 for x in lengths) / len(lengths)
        cv = (variance ** 0.5) / mean if mean > 0 else 0.0
        stats[f"{attr}_cv"] = round(cv, 4)
    return stats

@dataclass
class AIIncident:
    incident_id: str
    system_name: str
    timestamp: datetime
    severity: Literal["LOW", "MEDIUM", "HIGH", "CRITICAL"]
    description: str
    affected_users: int
    root_cause: str = ""
    corrective_action: str = ""
    resolved: bool = False
    nist_category: str = ""   # e.g. "Safety", "Fairness", "Robustness"

class IncidentLog:
    def __init__(self):
        self._incidents: list[AIIncident] = []

    def report(self, incident: AIIncident) -> None:
        self._incidents.append(incident)

    def open_incidents(self) -> list[AIIncident]:
        return [i for i in self._incidents if not i.resolved]

    def critical_count(self) -> int:
        return sum(1 for i in self._incidents if i.severity == "CRITICAL")

    def mttr_hours(self) -> float:
        """Mean time to resolve (hours) for resolved incidents."""
        resolved = [i for i in self._incidents if i.resolved]
        if not resolved:
            return 0.0
        # Placeholder — real implementation would use resolution_timestamp
        return 0.0
